def get_closest_vowel(s):
    """You are given a word. Your task is to locate the rightmost-applicable vowel that stands between 
    two consonants from the right side of the word (case sensitive).

    Vowels in the beginning and ending doesn't count. Return empty string if you didn't
    locate any vowel met the above condition. 

    You may assume that the given string contains English letter only.

    Example:
    get_closest_vowel("yogurt") ==> "u"
    get_closest_vowel("FULL") ==> "U"
    get_closest_vowel("quick") ==> ""
    get_closest_vowel("ab") ==> ""
    """
    if len(s) < 3:
        return ""

    vowels = {"a", "e", "i", "o", "u", "A", "E", 'O', 'U', 'I'}
    for i in range(len(s)-2, 0, -1):
        if s[i] in vowels:
            if (s[i+1] not in vowels) and (s[i-1] not in vowels):
                return s[i]
    return ""

