def digit_parity_counts(value):
    """Given an integer. return a tuple that has the number of even and odd digits respectively.

     Example:
        digit_parity_counts(-12) ==> (1, 1)
        digit_parity_counts(123) ==> (1, 2)
    """
    even_count = 0
    odd_count = 0
    for i in str(abs(value)):
        if int(i)%2==0:
            even_count +=1
        else:
            odd_count +=1
    return (even_count, odd_count)

