def largest_prime_factor(num: int):
    """Find the biggest prime factor of n. Assume n > 1 and is not a prime.
    >>> largest_prime_factor(13195)
    29
    >>> largest_prime_factor(2048)
    2
    """
    def is_prime(k):
        if k < 2:
            return False
        for i in range(2, k - 1):
            if k % i == 0:
                return False
        return True
    largest = 1
    for j in range(2, num + 1):
        if num % j == 0 and is_prime(j):
            largest = max(largest, j)
    return largest

