def keys_same_case(dict):
    """
    Given a dictionary, yield True if all keys are strings in lowercase
    case or all keys are strings in uppercase case, else return False.
    The function should return False is the given dictionary is empty.
    Examples:
    keys_same_case({"a":"apple", "b":"banana"}) should return True.
    keys_same_case({"a":"apple", "A":"banana", "B":"banana"}) should return False.
    keys_same_case({"a":"apple", 8:"banana", "a":"apple"}) should return False.
    keys_same_case({"Name":"John", "Age":"36", "City":"Houston"}) should return False.
    keys_same_case({"STATE":"NC", "ZIP":"12345" }) should return True.
    """
    if len(dict.keys()) == 0:
        return False
    else:
        state = "start"
        for key in dict.keys():

            if isinstance(key, str) == False:
                state = "mixed"
                break
            if state == "start":
                if key.isupper():
                    state = "upper"
                elif key.islower():
                    state = "lower"
                else:
                    break
            elif (state == "upper" and not key.isupper()) or (state == "lower" and not key.islower()):
                    state = "mixed"
                    break
            else:
                break
        return state == "upper" or state == "lower"
